# coding: utf-8
from typing import Dict, List, Optional, Union

from rainbow_admin.api import AdminApi
from rainbow_admin.file import FileGroup
from rainbow_admin.group import BaseGroup
from rainbow_admin.kv import KVGroup
from rainbow_admin.release import Release
from rainbow_admin.table import TableGroup
from rainbow_admin.template import Template
from rainbow_admin.utils import cached_property, logger


class RainbowAdmin(object):
    def __init__(
        self,
        app_id: str = None,
        user_id: str = None,
        secret_key: str = None,
        *,
        env: str = "Default",
        api: AdminApi = None,
        **kwargs,
    ):
        if api is not None:
            self.api = api
        else:
            self.api = AdminApi(app_id, user_id, secret_key, **kwargs)
        self.app_id = self.api.app_id
        self.env = env

        self._cache = None

    def get_group(
        self, group_name: str
    ) -> Optional[Union[BaseGroup, KVGroup, TableGroup, FileGroup]]:
        return self.groups.get(group_name)

    def get_group_by_id(
        self, group_id: int
    ) -> Optional[Union[BaseGroup, KVGroup, TableGroup, FileGroup]]:
        for v in self.groups.values():
            if v.group_id == group_id:
                return v

    @property
    def groups(self) -> Dict[str, Union[BaseGroup, KVGroup, TableGroup, FileGroup]]:
        if self._cache is None:
            groups = self.api.query_group_list(env_name=self.env)
            self._cache = {}
            for i in groups:
                if i["config_type"] == "GROUPCONFIG_KV":
                    self._cache[i["group_name"]] = KVGroup(**i, admin=self)
                elif i["config_type"] == "GROUPCONFIG_TABLE":
                    self._cache[i["group_name"]] = TableGroup(**i, admin=self)
                elif i["config_type"] == "GROUPCONFIG_FILE":
                    self._cache[i["group_name"]] = FileGroup(**i, admin=self)
                else:
                    logger.warning(f"分组 {i['group_name']} 为不支持的类型： {i['config_type']} ")
                    self._cache[i["group_name"]] = BaseGroup(**i, admin=self)
        return self._cache

    def create_group(
        self,
        group_name,
        description="",
        is_public=False,
        config_type=0,
        omit_approval=False,
        publish_type="DEFAULT",
        disable_file_auth=False,
    ):
        if isinstance(config_type, str):
            config_type = {"KV": 0, "TABLE": 1, "FILE": 2}.get(config_type.upper())
            if config_type is None:
                raise ValueError(
                    "config type should be one of (kv, table, file) or num 0-2, not %s",
                    config_type,
                )
        self.clear_cache()
        self.api.add_group(
            group_name,
            description,
            is_public,
            config_type,
            omit_approval,
            env_name=self.env,
            publish_type=publish_type,
            disable_file_auth=disable_file_auth,
        )

    def delete_group(self, group_id, group_name):
        self.clear_cache()
        return self.api.delete_group(group_id, group_name, self.env)

    def get_release_tasks(self, size=10, group_name=None) -> List[Release]:
        return [
            Release(**i, admin=self)
            for i in self.api.query_release_task_list(
                group_name=group_name, env_name=self.env, size=size
            )
        ]

    @property
    def templates(self):
        rsp = self.api.list_templates()['data']['pkgs']
        return [Template(**item, admin=self) for item in rsp]

    def get_template(self, name):
        for tpl in self.templates:
            if tpl.name == name:
                return tpl
        return None

    def create_template(self, name, desc):
        return self.api.create_template(name=name, desc=desc)

    # def update_template(self, name, desc):
    #     return self.api.update_template(name=name, desc=desc)

    # def delete_template(self, name):
    #     return self.api.delete_template(name=name)

    def get_release_task(self, task_id) -> Release:
        info = self.api.query_task_info(task_id)
        return Release(**info["task_info"], admin=self)

    @cached_property
    def rule_types(self):
        from .release import GrayRuleType

        return [GrayRuleType(**i) for i in self.api.query_gray_rule_types()]

    def __getitem__(self, group_name):
        return self.get_group(group_name=group_name)

    def __contains__(self, item):
        return item in self.groups

    def __str__(self) -> str:
        return f"{self.__class__.__name__}(app_id={self.app_id}, env={self.env})"

    __repr__ = __str__

    def clear_cache(self):
        self._cache = None

    def query_env_list(self) -> List[Dict]:
        return self.api.query_env_list()

    @cached_property
    def env_list(self) -> List[str]:
        return [i["env_name"] for i in self.api.query_env_list()]

    def switch_env(self, env_name) -> "RainbowAdmin":
        """切换环境，返回另一个`RainbowAdmin`实例

        :param env_name:
        :return:
        """
        return self.__class__(api=self.api, env=env_name)

    def add_env(self, env_name, env_type="PRODUCTION", desc=""):
        return self.api.change_env_info(1, env_name, env_type=env_type, env_desc=desc)

    def del_env(self, env_name, env_type):
        return self.api.change_env_info(2, env_name, env_type=env_type)

    def all_group_by_version(self, version_name):
        return self.api.all_group_by_version(version_name)['infos']
